const TEAM_NAME_MAP = { 'Ops': 'Operations', 'Eng': 'Engineering' };

async function getUserTeam() {
  const cachedTeam = sessionStorage.getItem('itb_user_team');
  if (cachedTeam) return cachedTeam;
  try {
    const response = await fetch('/api/user/teams');
    if (!response.ok) return '_default';
    const teams = await response.json();
    if (!teams || teams.length === 0) return '_default';
    const teamPriority = ['Leadership', 'Operations', 'Engineering', 'Product', 'Sales', 'Finance', 'HR'];
    const userTeamNames = teams.map(t => t.name);
    for (const priorityTeam of teamPriority) {
      if (userTeamNames.includes(priorityTeam)) {
        sessionStorage.setItem('itb_user_team', priorityTeam);
        return priorityTeam;
      }
    }
    const firstTeam = teams[0].name;
    sessionStorage.setItem('itb_user_team', firstTeam);
    return firstTeam;
  } catch (e) {
    return '_default';
  }
}

(async function () {
  const userTeam = await getUserTeam();
  const effectiveTeam = TEAM_CONFIGS[userTeam] ? userTeam : '_default';

  if (existingContainer && existingTeam === effectiveTeam && navLinks.children.length > 0) {
    window._itbNavbarBuildingFor = null;
    return;
  }

  window._itbNavbarBuildingFor = currentDashUid;

  const tagTeamName = effectiveTeam === '_default'
    ? '_default'
    : Object.entries(TEAM_NAME_MAP).find(([tag, grafana]) => grafana === effectiveTeam)?.[0] || effectiveTeam;

  const defaultConfig = TEAM_CONFIGS['_default'] || {};
  const teamConfig = effectiveTeam === '_default' ? {} : (TEAM_CONFIGS[effectiveTeam] || {});
  const defaultOrder = defaultConfig.dropdownOrder || [];
  const teamOrder = teamConfig.dropdownOrder || [];
  const mergedOrder = [...defaultOrder, ...teamOrder.filter(cat => !defaultOrder.includes(cat))];

  const CONFIG = {
    ...defaultConfig,
    ...teamConfig,
    categoryLinks: { ...(defaultConfig.categoryLinks || {}), ...(teamConfig.categoryLinks || {}) },
    categoryIcons: { ...(defaultConfig.categoryIcons || {}), ...(teamConfig.categoryIcons || {}) },
    dashboardIcons: { ...(defaultConfig.dashboardIcons || {}), ...(teamConfig.dashboardIcons || {}) },
    dropdownOrder: mergedOrder.length ? mergedOrder : defaultOrder,
    externalLinks: [...(defaultConfig.externalLinks || []), ...(teamConfig.externalLinks || [])],
    hoverDelay: 150
  };

  console.log('Navbar: Building for team:', effectiveTeam);

  const navEl = document.getElementById('itb-navbar');
  const navIndicator = document.getElementById('itb-nav-indicator');

  const oldContainer = document.getElementById('itb-global-dropdown');
  if (oldContainer) oldContainer.remove();
  if (window._itbNavClickHandler) document.removeEventListener('click', window._itbNavClickHandler);
  navLinks.innerHTML = '';

  let dropdownContainer = document.createElement('div');
  dropdownContainer.id = 'itb-global-dropdown';
  dropdownContainer.setAttribute('data-dash-uid', currentDashUid || '');
  dropdownContainer.setAttribute('data-team', effectiveTeam);
  dropdownContainer.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:99999;';
  document.body.appendChild(dropdownContainer);

  let activeDropdown = null;
  let hoverTimeout = null;
  let isOverMenu = false;
  let isOverToggle = false;

  // Indicator state management with session counter to prevent race conditions
  let indicatorHideTimeout = null;
  let indicatorHoverSession = 0;
  let indicatorShouldBeVisible = false;

  // MutationObserver to protect indicator from being hidden by stale timeouts
  if (navIndicator) {
    const indicatorObserver = new MutationObserver((mutations) => {
      for (const mutation of mutations) {
        if (mutation.attributeName === 'style') {
          if (indicatorShouldBeVisible && navIndicator.style.opacity === '0') {
            navIndicator.style.opacity = '1';
          }
        }
      }
    });
    indicatorObserver.observe(navIndicator, { attributes: true });
  }

  function parseNavTag(tag, targetTeam) {
    if (!tag) return null;
    const lowerTag = tag.toLowerCase();
    if (!lowerTag.startsWith('nav:')) return null;
    const parts = tag.slice(4).split(':');
    if (parts.length === 0) return null;
    const tagTeam = parts[0];
    const isDefaultTag = tagTeam.toLowerCase() === DEFAULT_TAG_NAME.toLowerCase();
    if (!isDefaultTag && tagTeam.toLowerCase() !== targetTeam.toLowerCase()) return null;
    if (parts.length === 1) return { type: 'simple' };
    if (parts.length >= 2) return { type: 'dropdown', category: parts[1], order: parts[2] ? parseInt(parts[2], 10) || 999 : 999 };
    return null;
  }

  function showIndicator(el) {
    if (!navIndicator || !navEl) return;

    // Clear any pending hide timeout
    if (indicatorHideTimeout) {
      clearTimeout(indicatorHideTimeout);
      indicatorHideTimeout = null;
    }

    // Increment session to invalidate any stale pending hides
    indicatorHoverSession++;
    indicatorShouldBeVisible = true;

    const rect = el.getBoundingClientRect();
    const navRect = navEl.getBoundingClientRect();
    navIndicator.style.opacity = '1';
    navIndicator.style.width = rect.width + 'px';
    navIndicator.style.left = (rect.left - navRect.left) + 'px';
  }

  function hideIndicator() {
    if (navIndicator) navIndicator.style.opacity = '0';
    indicatorShouldBeVisible = false;
  }

  function maybeHideIndicator() {
    const sessionAtSchedule = indicatorHoverSession;
    indicatorHideTimeout = setTimeout(() => {
      // Only hide if no new hover has happened since this was scheduled
      if (sessionAtSchedule === indicatorHoverSession) {
        hideIndicator();
      }
      indicatorHideTimeout = null;
    }, 10);
  }

  function createDropdownMenu(category, items) {
    const menu = document.createElement('div');
    menu.className = 'itb-dropdown-menu';
    menu.setAttribute('data-category', category);
    menu.style.cssText = 'position:absolute;width:auto;min-width:140px;max-width:400px;background:linear-gradient(to bottom,rgba(18,22,32,0.85),rgba(12,16,26,0.92));backdrop-filter:blur(12px);-webkit-backdrop-filter:blur(12px);border:1px solid rgba(90,110,145,0.2);border-radius:10px;padding:8px 0;box-shadow:0 15px 40px rgba(0,0,0,0.4),0 5px 15px rgba(0,0,0,0.3);pointer-events:auto;opacity:0;transform:translateY(-8px) scale(0.98);transition:opacity 0.2s ease,transform 0.2s ease;visibility:hidden;';
    menu.onmouseenter = function () { isOverMenu = true; };
    menu.onmouseleave = function () { isOverMenu = false; scheduleHide(); };

    items.sort((a, b) => a.order - b.order || a.title.localeCompare(b.title));
    items.forEach(item => {
      const link = document.createElement('a');
      link.href = item.url;
      if (item.external) link.target = '_blank';
      link.className = 'itb-dropdown-link';
      // No border-left, use accent bar instead to prevent subpixel rendering shifts
      link.style.cssText = 'display:flex;align-items:center;padding:10px 16px 10px 13px;color:#fff;opacity:0.9;text-decoration:none;font-size:13px;font-family:Roboto,Arial,sans-serif;white-space:nowrap;position:relative;overflow:hidden;';

      // Create accent bar (replaces border-left to avoid rendering shifts)
      const accentBar = document.createElement('div');
      accentBar.className = 'accent-bar';
      accentBar.style.cssText = 'position:absolute;left:0;top:0;width:3px;height:100%;background:transparent;transition:background 0.2s ease;pointer-events:none;';
      link.appendChild(accentBar);

      // Create background gradient overlay
      const bgOverlay = document.createElement('div');
      bgOverlay.style.cssText = 'position:absolute;top:0;left:0;width:0;height:100%;background:linear-gradient(to right,rgba(50,116,217,0.10) 0%,rgba(50,116,217,0.02) 100%);transition:width 0.25s ease-out;z-index:0;pointer-events:none;';
      link.appendChild(bgOverlay);

      link.onmouseenter = function () {
        this.classList.add('itb-dropdown-link-hover');
        accentBar.style.background = '#3274d9';
        bgOverlay.style.width = '100%';
        // No color/opacity change to prevent subpixel rendering shifts
      };
      link.onmouseleave = function () {
        this.classList.remove('itb-dropdown-link-hover');
        accentBar.style.background = 'transparent';
        bgOverlay.style.width = '0';
      };
      link.onclick = function () { hideAllDropdowns(); };

      if (item.faIcon) {
        const icon = document.createElement('i');
        icon.className = 'fa-solid ' + item.faIcon;
        icon.style.cssText = 'width:20px;margin-right:10px;text-align:center;font-size:14px;opacity:0.7;flex-shrink:0;';
        link.appendChild(icon);
      } else if (item.icon) {
        const img = document.createElement('img');
        img.src = item.icon;
        img.style.cssText = 'width:20px;height:20px;margin-right:10px;border-radius:4px;object-fit:cover;flex-shrink:0;';
        img.onerror = function () { this.style.display = 'none'; };
        link.appendChild(img);
      } else if (item.title && CONFIG.dashboardIcons[item.title]) {
        const icon = document.createElement('i');
        icon.className = 'fa-solid ' + CONFIG.dashboardIcons[item.title];
        icon.style.cssText = 'width:20px;margin-right:10px;text-align:center;font-size:14px;opacity:0.7;flex-shrink:0;';
        link.appendChild(icon);
      }

      const span = document.createElement('span');
      span.textContent = item.title;
      link.appendChild(span);
      menu.appendChild(link);
    });
    return menu;
  }

  function showDropdown(category, toggleEl) {
    if (hoverTimeout) clearTimeout(hoverTimeout);

    // If this dropdown is already open, don't reposition it
    if (activeDropdown === category) {
      return;
    }

    dropdownContainer.querySelectorAll('.itb-dropdown-menu').forEach(m => {
      if (m.getAttribute('data-category') !== category) {
        m.style.opacity = '0';
        m.style.transform = 'translateY(-8px) scale(0.98)';
        m.style.visibility = 'hidden';
      }
    });
    document.querySelectorAll('.dropdown-toggle.dropdown-open').forEach(t => {
      if (t.getAttribute('data-dropdown') !== category) t.classList.remove('dropdown-open');
    });
    const menu = dropdownContainer.querySelector('[data-category="' + category + '"]');
    if (!menu) return;
    const rect = toggleEl.getBoundingClientRect();
    const viewportWidth = window.innerWidth;

    menu.style.top = (rect.bottom + 4) + 'px';
    menu.style.left = rect.left + 'px';
    menu.style.opacity = '1';
    menu.style.transform = 'translateY(0) scale(1)';
    menu.style.visibility = 'visible';

    requestAnimationFrame(() => {
      const menuRect = menu.getBoundingClientRect();
      if (menuRect.right > viewportWidth - 10) {
        menu.style.left = Math.max(10, viewportWidth - menuRect.width - 10) + 'px';
      }
    });

    toggleEl.classList.add('dropdown-open');
    activeDropdown = category;
  }

  function hideDropdownsOnly() {
    dropdownContainer.querySelectorAll('.itb-dropdown-menu').forEach(m => {
      m.style.opacity = '0';
      m.style.transform = 'translateY(-8px) scale(0.98)';
      m.style.visibility = 'hidden';
    });
    document.querySelectorAll('.dropdown-toggle.dropdown-open').forEach(t => {
      t.classList.remove('dropdown-open');
      // Reset the hover styles when dropdown closes
      applyNavItemHoverStyles(t, false);
    });
    activeDropdown = null;
  }

  function hideAllDropdowns() {
    hideDropdownsOnly();
    hideIndicator();
  }

  function scheduleHide() {
    if (hoverTimeout) clearTimeout(hoverTimeout);
    hoverTimeout = setTimeout(() => { if (!isOverMenu && !isOverToggle) hideDropdownsOnly(); }, CONFIG.hoverDelay);
  }

  // Shared hover style application for nav items
  function applyNavItemHoverStyles(el, isHover) {
    // Check if this is a dropdown toggle that's currently open - keep styles if so
    const isDropdownOpen = el.classList.contains('dropdown-open');

    if (isHover || isDropdownOpen) {
      el.style.color = '#fff';
      el.style.textShadow = '0 0 8px rgba(50,116,217,0.6)';
    } else {
      el.style.color = 'rgba(255,255,255,0.85)';
      el.style.textShadow = 'none';
    }
  }

  function createNavItem(category) {
    const li = document.createElement('li');
    li.className = 'nav-item';
    const toggle = document.createElement('span');
    toggle.className = 'dropdown-toggle';
    toggle.setAttribute('data-dropdown', category);
    // Base styles matching simple links
    toggle.style.cssText = 'display:flex;align-items:center;gap:6px;padding:8px 14px;color:rgba(255,255,255,0.85);font-size:13px;font-weight:500;text-decoration:none;transition:all 0.2s ease;cursor:pointer;';

    if (CONFIG.categoryIcons[category]) {
      const iconSpan = document.createElement('span');
      iconSpan.className = 'nav-icon';
      iconSpan.innerHTML = CONFIG.categoryIcons[category];
      toggle.appendChild(iconSpan);
    }
    const textSpan = document.createElement('span');
    textSpan.textContent = category;
    toggle.appendChild(textSpan);

    toggle.onmouseenter = function () {
      isOverToggle = true;
      showDropdown(category, this);
      showIndicator(this);
      applyNavItemHoverStyles(this, true);
    };
    toggle.onmouseleave = function () {
      isOverToggle = false;
      scheduleHide();
      maybeHideIndicator();
      applyNavItemHoverStyles(this, false);
    };
    if (CONFIG.categoryLinks && CONFIG.categoryLinks[category]) {
      toggle.onclick = function () { window.location.href = CONFIG.categoryLinks[category]; };
    }
    li.appendChild(toggle);
    return li;
  }

  function createSimpleLink(db) {
    const li = document.createElement('li');
    li.className = 'nav-item';
    const a = document.createElement('a');
    a.href = '/d/' + db.uid + '/' + (db.slug || '');
    a.textContent = db.title;
    // Base styles
    a.style.cssText = 'display:flex;align-items:center;gap:6px;padding:8px 14px;color:rgba(255,255,255,0.85);font-size:13px;font-weight:500;text-decoration:none;transition:all 0.2s ease;';

    a.onmouseenter = function () {
      if (activeDropdown) hideDropdownsOnly();
      showIndicator(this);
      applyNavItemHoverStyles(this, true);
    };
    a.onmouseleave = function () {
      maybeHideIndicator();
      applyNavItemHoverStyles(this, false);
    };
    li.appendChild(a);
    return li;
  }

  const dropdowns = {};
  const simpleLinks = [];
  let navBuilt = false;

  (CONFIG.externalLinks || []).forEach(link => {
    if (!dropdowns[link.category]) dropdowns[link.category] = [];
    dropdowns[link.category].push({ title: link.title, url: link.url, icon: link.icon, faIcon: link.faIcon, order: link.order, external: true });
  });

  function buildNav() {
    if (navBuilt) return;
    navBuilt = true;
    const categoriesWithItems = Object.keys(dropdowns).filter(cat => dropdowns[cat] && dropdowns[cat].length > 0);
    const sortedCategories = categoriesWithItems.sort((a, b) => {
      const iA = CONFIG.dropdownOrder.indexOf(a);
      const iB = CONFIG.dropdownOrder.indexOf(b);
      if (iA === -1 && iB === -1) return a.localeCompare(b);
      if (iA === -1) return 1;
      if (iB === -1) return -1;
      return iA - iB;
    });
    sortedCategories.forEach(cat => {
      dropdownContainer.appendChild(createDropdownMenu(cat, dropdowns[cat]));
      navLinks.appendChild(createNavItem(cat));
    });
    simpleLinks.sort((a, b) => a.title.localeCompare(b.title));
    simpleLinks.forEach(db => navLinks.appendChild(createSimpleLink(db)));
    console.log('Navbar: Built', sortedCategories.length, 'dropdowns | Simple links:', simpleLinks.length);
    window._itbNavbarBuildingFor = null;
  }

  fetch('/api/search?type=dash-db&limit=1000')
    .then(r => r.json())
    .then(dashboards => {
      dashboards.forEach(db => {
        if (!db.tags) return;
        db.tags.forEach(tag => {
          const parsed = parseNavTag(tag, tagTeamName);
          if (!parsed) return;
          if (parsed.type === 'simple') {
            if (!simpleLinks.some(x => x.uid === db.uid)) simpleLinks.push(db);
          } else if (parsed.type === 'dropdown') {
            if (!dropdowns[parsed.category]) dropdowns[parsed.category] = [];
            if (!dropdowns[parsed.category].some(x => x.uid === db.uid)) {
              dropdowns[parsed.category].push({ title: db.title, url: '/d/' + db.uid + '/' + (db.slug || ''), order: parsed.order, uid: db.uid });
            }
          }
        });
      });
      buildNav();
    })
    .catch(err => { console.error('Navbar: Error fetching dashboards:', err); buildNav(); });

  window._itbNavClickHandler = function (e) {
    if (!e.target.closest('.dropdown-toggle') && !e.target.closest('.itb-dropdown-menu')) hideAllDropdowns();
  };
  document.addEventListener('click', window._itbNavClickHandler);

  if (!window._itbNavCleanupRegistered) {
    window._itbNavCleanupRegistered = true;
    const observer = new MutationObserver(() => {
      if (!document.getElementById('itb-navbar')) {
        const container = document.getElementById('itb-global-dropdown');
        if (container) container.remove();
        window._itbNavbarBuildingFor = null;
      }
    });
    observer.observe(document.body, { childList: true, subtree: true });
  }
})();

