/* Navigation container - darker blueish frosted glass */
.custom-nav {
  width: 100%;
  background: linear-gradient(to bottom, rgba(18, 22, 32, 0.7) 25%, rgba(12, 16, 26, 0.88) 100%);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  display: flex;
  align-items: center;
  padding: 0 15px;
  font-family: 'Roboto', 'Helvetica Neue', Arial, sans-serif;
  border-bottom: 1px solid rgba(90, 110, 145, 0.15);
  border-bottom-left-radius: 15px;
  border-bottom-right-radius: 15px;
  height: 40px;
  position: relative;
}

.nav-logo {
  display: flex;
  align-items: center;
  margin-right: 12px;
  transition: transform 0.2s ease;
}

.nav-logo:hover {
  transform: scale(1.12);
}

.nav-links {
  display: flex;
  list-style: none;
  margin: 0;
  padding: 0;
  align-items: center;
}

/* Individual navigation items */
.nav-item {
  position: relative;
  margin-right: 6px;
  display: flex;
  align-items: center;
}

.nav-item > a,
.dropdown-toggle {
  color: rgba(255, 255, 255, 0.92) !important;
  text-decoration: none !important;
  padding: 8px 16px;
  font-size: 14px;
  line-height: 1;
  display: flex;
  align-items: center;
  gap: 8px;
  border-radius: 6px;
  cursor: pointer;
  transition: all 0.2s ease;
  z-index: 1;
  overflow: hidden;
}

/* Subtle hover effect - soft gradient */
.nav-item > a:before,
.dropdown-toggle:before {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
  height: 0;
  background: linear-gradient(to top,
              rgba(50, 116, 217, 0.08) 0%,
              rgba(50, 116, 217, 0.01) 100%);
  transition: height 0.3s ease;
  z-index: -1;
  border-radius: 6px;
}

.nav-item > a:hover,
.dropdown-toggle:hover,
.dropdown-toggle.dropdown-open {
  color: #ffffff !important;
  transform: translateY(-1px);
  text-shadow: 0 0 8px rgba(50, 116, 217, 0.6);
}

.nav-item > a:hover:before,
.dropdown-toggle:hover:before,
.dropdown-toggle.dropdown-open:before {
  height: 100%;
}

/* Nav icon styling */
.nav-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0.7;
  transition: opacity 0.2s ease;
  flex-shrink: 0;
  position: relative;
  top: 0;
}

.nav-icon svg {
  display: block;
  stroke-linecap: round;
  stroke-linejoin: round;
}

/* Text positioning in nav items */
.nav-item > a,
.dropdown-toggle {
  position: relative;
}

.dropdown-toggle > span:not(.nav-icon),
.nav-item > a {
  position: relative;
  top: 1px;
}

.dropdown-toggle:hover .nav-icon,
.dropdown-toggle.dropdown-open .nav-icon {
  opacity: 1;
}

/* Dropdown arrow */
.dropdown-toggle::after {
  content: '';
  display: inline-block;
  margin-left: 4px;
  border-left: 4px solid transparent;
  border-right: 4px solid transparent;
  border-top: 4px solid currentColor;
  transition: transform 0.25s ease;
  flex-shrink: 0;
}

.dropdown-toggle.dropdown-open::after {
  transform: rotate(180deg);
}

/* Active navigation item */
.nav-item > a.active {
  color: #ffffff;
  background: rgba(50, 116, 217, 0.15);
}

.nav-indicator {
  position: absolute;
  bottom: 0;
  height: 2px;
  background: linear-gradient(90deg, rgba(50, 116, 217, 0.8), rgba(82, 148, 255, 0.8));
  transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);
  border-radius: 2px;
  box-shadow: 0 0 4px rgba(50, 116, 217, 0.3);
  opacity: 0;
  pointer-events: none;
}

/* Subtle indicator animation on hover */
.nav-item > a:hover + .nav-indicator,
.nav-indicator:hover {
  box-shadow: 0 0 6px rgba(50, 116, 217, 0.4);
}

/* Dropdown menu link styling */
.itb-dropdown-menu .itb-dropdown-link {
  display: flex;
  align-items: center;
  padding: 10px 12px 10px 10px;
  color: rgba(255, 255, 255, 0.92);
  text-decoration: none;
  font-size: 13px;
  font-family: Roboto, Arial, sans-serif;
  border-left: 3px solid transparent;
  transition: all 0.15s ease;
  position: relative;
  overflow: hidden;
}

/* Gradient hover effect for dropdown links (same as nav items) */
.itb-dropdown-menu .itb-dropdown-link:before {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
  height: 0;
  background: linear-gradient(to top,
              rgba(50, 116, 217, 0.15) 0%,
              rgba(50, 116, 217, 0.03) 100%);
  transition: height 0.2s ease;
  z-index: -1;
}

.itb-dropdown-menu .itb-dropdown-link:hover,
.itb-dropdown-menu .itb-dropdown-link.itb-dropdown-link-hover {
  color: #fff;
  border-left-color: #3274d9;
  padding-left: 14px;
}

.itb-dropdown-menu .itb-dropdown-link:hover:before,
.itb-dropdown-menu .itb-dropdown-link.itb-dropdown-link-hover:before {
  height: 100%;
}

/* Spacer to push logout to right */
.nav-spacer {
  flex: 1;
}

/* Logout button - icon only, text on hover */
.nav-logout {
  display: flex;
  align-items: center;
  gap: 0;
  color: rgba(255, 255, 255, 0.5);
  text-decoration: none;
  padding: 8px;
  font-size: 13px;
  line-height: 1;
  border-radius: 6px;
  transition: all 0.25s ease;
  overflow: hidden;
}

.nav-logout:hover {
  color: #ff6b6b;
  background: rgba(255, 107, 107, 0.12);
  gap: 8px;
  padding: 8px 12px;
}

.nav-logout svg {
  display: block;
  flex-shrink: 0;
  transition: all 0.2s ease;
}

.nav-logout .logout-text {
  max-width: 0;
  opacity: 0;
  white-space: nowrap;
  transition: max-width 0.25s ease, opacity 0.2s ease;
}

.nav-logout:hover .logout-text {
  max-width: 80px;
  opacity: 1;
}

/* Responsive adjustments */
@media (max-width: 768px) {
  .nav-item > a,
  .dropdown-toggle {
    padding: 8px 12px;
    font-size: 13px;
  }
}
